select
  u.*, date_format(u.birthday, '%Y-%m-%d') as birthday2,
  ss.username,s.storeName
from user_info u
left join sys_user ss on ss.user_id=u.sysUserId
left join device d on u.userId=d.proxyId
left join store_address s on d.storeAddressId=s.storeAddrId

	u.isDel=1
	
        AND u.nickname like concat('%',#{nickname},'%')
    
    
        AND u.phone like concat('%',#{phone},'%')
    
    
        AND s.storeName like concat('%',#{storeName},'%')
    
    
        AND s.storeId in (${storeIds})
    
    
        AND u.sex = #{sex}
    
    
        AND u.wtState = #{wtState}
    
    
        AND u.auditStatus = #{auditStatus}
    
    
        AND u.delTime >= #{startTime}
    
    
        AND u.delTime <= #{endTime}
    
    
        AND u.remark like concat('%',#{remark},'%')
    


    
        order by ${sidx} ${order}
    
    
        order by u.createdDate desc
    


    limit #{offset}, #{limit}

