mapper.select:
        select
        d.deviceId, u.userId,u.nickname,u.phone,u.sex,date_format(u.birthday, '%Y-%m-%d') as birthday,u.height,u.weight,u.remark,u.faceStatus,
        u.auditStatus,u.wtState,
        d.createTime as createdDate, s.storeName, d.status,d.inOutNum,
        d.type,(select ct.ctName from card_type ct where ct.cardType=d.type limit 1) as ctName,
        (select fc.cardName from fit_card fc where fc.fitCardId = d.fitCardId limit 1) as cardName,
        date_format(d.validityDate, '%Y-%m-%d') as validityDate
        from store_address s inner join device d on d.storeAddressId=s.storeAddrId
        inner join user_info u on u.userId=d.proxyId
         
			u.isDel=0
            
                AND s.storeId=#{storeId}
            
            
                AND s.storeId in (${storeIds})
            
            
                AND u.nickname like concat('%',#{nickname},'%')
            
            
                AND u.phone like concat('%',#{phone},'%')
            
            
                AND u.sex = #{sex}
                     
            
                AND u.auditStatus = #{auditStatus}
                  
            
                AND u.wtState = #{wtState}
            
            
                AND s.storeName like concat('%',#{storeName},'%')
            
            
                AND d.validityDate >= #{startTime}
            
            
                AND d.validityDate <= #{endTime}
            
            
                AND d.autoPay =#{autoPay}
            
            
                AND d.autoPay > 0
            
            
                AND d.selecteFree = #{selecteFree}
            
            
                AND u.remark like concat('%',#{remark},'%')
                    
            
                AND d.status = #{status}
            
        
        order by d.createTime desc

