        d.deviceId, u.userId, u.nickname, u.phone, u.sex, date_format(u.birthday, '%Y-%m-%d') as birthday,
               u.height, u.weight, u.faceStatus, u.remark, u.auditStatus,u.wtState,u.headImgUrl,
        u.createdDate, s.storeName, d.status,d.inOutNum,d.autoPay,d.selecteFree,
        d.type,(select ct.ctName from card_type ct where ct.cardType=d.type limit 1) as ctName,
        (select fc.cardName from fit_card fc where fc.fitCardId = d.fitCardId limit 1) as cardName,
        date_format(d.validityDate, '%Y-%m-%d') as validityDate, d.createTime as buyTime, u.contractId,
        (select group_concat(storeName) from store_address where find_in_set(storeAddrId, d.storeAddrIds)) as supportStoreName
        from store_address s inner join device d on d.storeAddressId=s.storeAddrId
        inner join user_info u on u.userId=d.proxyId
         
			u.isDel=0
            
                AND s.storeId=#{storeId}
            
            
                AND s.storeId in (${storeIds})
            
            
                AND u.nickname like concat('%',#{nickname},'%')
            
            
                AND u.phone like concat('%',#{phone},'%')
            
            
