                AND d.validityDate <= #{endTime}
            
            
                AND d.autoPay =#{autoPay}
            
            
                AND d.autoPay > 0
            
            
                AND d.selecteFree = #{selecteFree}
            
            
                AND u.remark like concat('%',#{remark},'%')
                    
            
                AND d.status = #{status}
            
        
        
            
                order by ${sidx} ${order}
            
            
