select 
c.*,ui.nickname,ui.phone,su.username as sysUserName

,o.finishTime as payTime,sa.storeName
        
 FROM coupon c
INNER JOIN user_info ui on c.userId=ui.userId
LEFT JOIN device d on c.userId = d.proxyId
LEFT JOIN sys_user su on su.user_id=c.sysUserId

LEFT JOIN card_order o on o.couponId = c.couponId and o.status=4
LEFT JOIN store_address sa on sa.storeAddrId = o.storeAddressId


	ui.isDel=0
    
        AND ui.phone like concat('%',#{phone},'%')
    
    
        AND c.couponTitle like concat('%',#{couponTitle},'%')
    
    
        AND sa.storeName like concat('%',#{storeName},'%')
    
    
        AND c.operateStoreId = #{storeName}
    
    
        AND c.couponStatus = #{couponStatus}
    
    
        AND c.couponType = #{couponType}
    
    
        AND c.couponNew = #{couponNew}
    
    
        AND c.operateStore like concat('%',#{operateStore},'%')
    
    
        AND su.username like concat('%',#{sysUserName},'%')
    
    
        AND c.createdDate between #{startTime} and #{endTime}
    
    
        AND c.operateStoreId = #{storeId}
    
    
        AND c.operateStoreId in (${storeIds})
    
    
        AND (HaveCommonElements(c.storeAddrIds, #{storeAddrIds}) or c.storeAddrIds is null or c.storeAddrIds='')
    
    
        AND c.couponStatus = #{couponStatus}
    
    
        AND d.validityTime >= #{startTime}
    
    
        AND d.validityTime <= #{endTime}
    
    
        AND o.finishTime >= #{startTime}
    
    
        AND o.finishTime <= #{endTime}
    

order by c.createdDate desc

    limit #{offset}, #{limit}

